import React, { useState, useCallback } from 'react';
import {
  GoabFormItem,
  GoabInput,
  GoabButton,
  GoabButtonGroup
} from '@abgov/react-components';

interface FormStepProps {
  stepNumber: number;
  totalSteps: number;
  title: string;
  description?: string;
  onBack: () => void;
  onContinue: () => void;
  children: React.ReactNode;
}

export function FormStep({
  stepNumber,
  totalSteps,
  title,
  description,
  onBack,
  onContinue,
  children
}: FormStepProps) {
  return (
    <div className="form-page">
      <div className="form-header">
        {stepNumber > 1 && (
          <button type="button" className="back-link" onClick={onBack}>
            Back
          </button>
        )}
        <p className="step-indicator">Step {stepNumber} of {totalSteps}</p>
      </div>

      <h1 className="step-title">{title}</h1>
      {description && (
        <p className="step-description">{description}</p>
      )}

      <form className="question-group" onSubmit={(e) => { e.preventDefault(); onContinue(); }}>
        {children}

        <div className="form-actions">
          <GoabButtonGroup alignment="start" gap="relaxed">
            <GoabButton type="primary" onClick={onContinue}>
              Save and continue
            </GoabButton>
          </GoabButtonGroup>
        </div>
      </form>
    </div>
  );
}

// Example usage:
function PersonalInfoStep() {
  const [name, setName] = useState('');
  const [nameError, setNameError] = useState('');

  const handleContinue = () => {
    if (!name.trim()) {
      setNameError('Enter your full name');
      return;
    }
    // Save and navigate to next step
    console.log('Proceeding with name:', name);
  };

  return (
    <FormStep
      stepNumber={1}
      totalSteps={6}
      title="Personal Information"
      description="Tell us about yourself"
      onBack={() => console.log('Go back')}
      onContinue={handleContinue}
    >
      <GoabFormItem
        label="What is your full legal name?"
        error={nameError}
        requirement="required"
        helpText="Enter your name as it appears on official documents"
      >
        <GoabInput
          name="fullName"
          value={name}
          onChange={(e) => { setName(e.value); setNameError(''); }}
          error={!!nameError}
          width="50ch"
        />
      </GoabFormItem>
    </FormStep>
  );
}

